const allTitles = $input.first().json.all_titles;

const prompt = [
  '다음은 오늘 뉴스 헤드라인 제목 목록입니다.',
  '현재 가장 중요하고 관심을 가질 만한 검색 키워드 10개를 선정해주세요.',
  'IT에 관심이 많고 세계, 사회 순서로 관심이 있습니다.',
  '유사하거나 중복 의미의 키워드는 최소화하세요.',
  '서두나 부연 설명 없이 키워드 10개만 쉼표(,)로 구분해 한 줄로만 답변하세요.',
  '',
  '[답변 예시]',
  'A, B, C, D, E, F, G, H, I, J',
  '',
  '[제목 목록]',
  allTitles
].join('\n');

return [{
  json: {
    contents: [{
      parts: [{ text: prompt }]
    }]
  }
}];

const text = $input.first().json.candidates[0].content.parts[0].text;

const keywords = text
  .split(',')
  .map(k => k.replace(/[*#\n]/g, '').trim())
  .filter(k => k.length > 0 && k.length <= 20);

return keywords.map(keyword => ({ json: { keyword } }));
